/* eslint-disable no-console */
import { SdoPoint } from '../../rest';
export class PointService {
    constructor(configuration, debug) {
        this.pointClient = new SdoPoint(configuration);
        this.debug = debug;
    }
    async getCost() {
        const response = await this.pointClient.getCost();
        if (this.debug)
            console.log(`response: ${JSON.stringify(response.data, null, 2)}`);
        return response.data;
    }
    async listPoints() {
        const response = await this.pointClient.listPoints();
        if (this.debug)
            console.log(`response: ${JSON.stringify(response.data, null, 2)}`);
        return response.data;
    }
}
